_OUR_IP_CACHE = None


def _get_our_ip():
    """Get our public IP (AWS) — cached, tries multiple sources"""
    global _OUR_IP_CACHE
    if _OUR_IP_CACHE:
        return _OUR_IP_CACHE
    import urllib.request
    for url in ("https://api.ipify.org", "https://checkip.amazonaws.com", "https://icanhazip.com"):
        try:
            req = urllib.request.Request(url, headers={"User-Agent": "curl/8.0"})
            with urllib.request.urlopen(req, timeout=5) as resp:
                _OUR_IP_CACHE = resp.read().decode().strip()
                return _OUR_IP_CACHE
        except:
            continue
    return None


def _socks5_connect(proxy_ip, proxy_port, target_host, target_port, timeout=5):
    """Full SOCKS5 handshake with CONNECT — supports no-auth and user/pass auth.
    Returns (success, socket).
    """
    import socket as _sock
    try:
        s = _sock.socket(_sock.AF_INET, _sock.SOCK_STREAM)
        s.settimeout(timeout)
        s.connect((proxy_ip, proxy_port))

        # Auth negotiation: offer no auth (0x00) and user/pass (0x02)
        s.sendall(b"\x05\x02\x00\x02")  # SOCKS5, 2 methods: no auth, user/pass
        resp = s.recv(2)
        if len(resp) < 2:
            s.close()
            return False, None

        # If server chose user/pass (0x02), try with empty creds
        if resp[1] == 0x02:
            s.sendall(b"\x01\x00\x00")  # Version 1, empty username, empty password
            auth_resp = s.recv(2)
            if len(auth_resp) < 2 or auth_resp[1] != 0x00:
                s.close()
                return False, None
        elif resp[1] != 0x00:
            s.close()
            return False, None

        # CONNECT request with domain name (ATYP=0x03)
        host_encoded = target_host.encode()
        if len(host_encoded) > 255:
            s.close()
            return False, None

        msg = (b"\x05\x01\x00\x03" +
               bytes([len(host_encoded)]) +
               host_encoded +
               target_port.to_bytes(2, 'big'))
        s.sendall(msg)

        # Read response header: VER, REP, RSV, ATYP
        hdr = s.recv(4)
        if len(hdr) < 4 or hdr[1] != 0x00:
            s.close()
            return False, None

        # Drain BND.ADDR + BND.PORT
        atyp = hdr[3]
        if atyp == 0x01:       # IPv4
            s.recv(6)
        elif atyp == 0x03:     # Domain name
            dl = s.recv(1)[0]
            s.recv(dl + 2)
        elif atyp == 0x04:     # IPv6
            s.recv(18)
        else:
            s.recv(6)          # fallback

        return True, s
    except:
        return False, None


def _extract_http_body(response):
    """Extract body from raw HTTP response bytes"""
    if b"\r\n\r\n" in response:
        _, body = response.split(b"\r\n\r\n", 1)
        return body.decode(errors="replace")
    return ""


def test_proxy_connect(proxy, timeout=5, total_timeout=8):
    """Full proxy validation: CONNECT test + HTTP GET through proxy + IP verification.

    For SOCKS5 proxies: does a proper SOCKS5 handshake then HTTP GET via tunnel.
    For HTTP proxies: uses urllib ProxyHandler to fetch httpbin.org/ip.

    Returns (success: bool, response_time_ms: float)
    Returns (False, 0) on any failure.
    """
    ip = proxy["ip"]
    port = int(proxy["port"])
    protocol = proxy.get("protocol", "socks5").lower()
    start = time.time()

    our_ip = _get_our_ip()

    # ── SOCKS5 proxy ──
    if protocol.startswith("socks"):
        for target_host, target_port in [("httpbin.org", 80), ("api.ipify.org", 80)]:
            success, sock = _socks5_connect(ip, port, target_host, target_port, timeout)
            if not success:
                continue

            # HTTP GET through the established tunnel
            try:
                sock.sendall(
                    b"GET /ip HTTP/1.1\r\n"
                    b"Host: " + target_host.encode() + b"\r\n"
                    b"User-Agent: curl/8.0\r\n"
                    b"Connection: close\r\n\r\n"
                )
                response = b""
                while time.time() - start < total_timeout:
                    try:
                        chunk = sock.recv(4096)
                        if not chunk:
                            break
                        response += chunk
                    except socket.timeout:
                        break
                    except BlockingIOError:
                        break

                if b"HTTP/1.1 200" in response or b"HTTP/1.0 200" in response:
                    body = _extract_http_body(response)
                    try:
                        import json as _json
                        data = _json.loads(body)
                        origin = data.get("origin", "") or data.get("ip", "")
                        proxy_ip_resp = origin.split(",")[0].strip()
                        if proxy_ip_resp and our_ip and proxy_ip_resp != our_ip:
                            elapsed = (time.time() - start) * 1000
                            return True, round(elapsed, 1)
                        elif proxy_ip_resp and not our_ip:
                            # Can't verify but got a valid response
                            elapsed = (time.time() - start) * 1000
                            return True, round(elapsed, 1)
                    except Exception:
                        # Valid 200 but couldn't parse body — still counts as working
                        elapsed = (time.time() - start) * 1000
                        return True, round(elapsed, 1)
            except Exception:
                pass
            finally:
                try:
                    sock.close()
                except Exception:
                    pass

        return False, 0

    # ── HTTP proxy (use urllib with ProxyHandler) ──
    else:
        import urllib.request
        try:
            proxy_handler = urllib.request.ProxyHandler({
                'http': f'http://{ip}:{port}',
                'https': f'http://{ip}:{port}',
            })
            opener = urllib.request.build_opener(proxy_handler)

            req = urllib.request.Request(
                "http://httpbin.org/ip",
                headers={"User-Agent": "curl/8.0"}
            )
            with opener.open(req, timeout=total_timeout) as resp:
                body = resp.read().decode()
                import json as _json
                data = _json.loads(body)
                origin = data.get("origin", "").split(",")[0].strip()
                if our_ip and origin and origin != our_ip:
                    elapsed = (time.time() - start) * 1000
                    return True, round(elapsed, 1)
                elif origin and not our_ip:
                    elapsed = (time.time() - start) * 1000
                    return True, round(elapsed, 1)
                return False, 0
        except Exception:
            return False, 0


def find_working_proxy(proxies, max_checks=25):
    """Find fastest working proxy by testing and sorting by response time.
    Returns the fastest proxy dict or None.
    """
    pool = list(proxies)
    random.shuffle(pool)
    results = []

    for p in pool[:max_checks]:
        success, speed = test_proxy_connect(p)
        if success:
            results.append((speed, p))
            if len(results) >= 3:
                break

    if not results:
        return None

    results.sort(key=lambda x: x[0])  # Fastest first
    return results[0][1]


def fetch_public_proxies(max_proxies=50):
    """Auto-fetch free proxies from public APIs for rotation"""
    proxies = []
    sources = [
        ("https://api.proxyscrape.com/v4/free-proxy-list/get?request=displayproxies&proxy_format=protocolipport&format=json&limit=30", "proxyscrape"),
        ("https://raw.githubusercontent.com/TheSpeedX/PROXY-List/master/socks5.txt", "speedx_socks5"),
        ("https://raw.githubusercontent.com/roosterkid/openproxylist/main/SOCKS5_RAW.txt", "roosterkit"),
        ("https://raw.githubusercontent.com/monosans/proxy-list/main/proxies/socks5.txt", "monosans"),
        ("https://raw.githubusercontent.com/proxifly/free-proxy-list/main/proxies/all/data.json", "proxifly"),
    ]
    import urllib.request
    for url, source in sources:
        try:
            req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
            with urllib.request.urlopen(req, timeout=8) as resp:
                raw = resp.read().decode()
            if source == "proxyscrape":
                import json as j
                data = j.loads(raw)
                for p in data.get("proxies", []):
                    proxies.append({
                        "ip": p.get("ip", p.get("proxy", "")),
                        "port": str(p.get("port", p.get("proxy", "").split(":")[1] if ":" in p.get("proxy", "") else "")),
                        "protocol": p.get("protocol", "socks5"),
                    })
            elif source in ("speedx_socks5", "roosterkit", "monosans"):
                for line in raw.strip().split("\n"):
                    line = line.strip()
                    if line and ":" in line and not line.startswith("#"):
                        parts = line.split(":")
                        proxies.append({"ip": parts[0], "port": parts[1], "protocol": "socks5"})
            elif source == "proxifly":
                import json as j
                data = j.loads(raw)
                # Array format: [{ip, port, protocol/type}, ...]
                if isinstance(data, list):
                    for p in data:
                        ip = p.get("ip", "")
                        port = str(p.get("port", ""))
                        proto = p.get("protocol", p.get("type", "socks5")).lower()
                        if ip and port:
                            proxies.append({"ip": ip, "port": port, "protocol": proto})
                # Dict format: {"proxies": [...]} or {"data": [...]}
                elif isinstance(data, dict):
                    items = data.get("proxies", data.get("data", []))
                    for p in items:
                        ip = p.get("ip", "")
                        port = str(p.get("port", ""))
                        proto = p.get("protocol", p.get("type", "socks5")).lower()
                        if ip and port:
                            proxies.append({"ip": ip, "port": port, "protocol": proto})
        except:
            pass
    # Deduplicate
    seen = set()
    unique = []
    for p in proxies:
        key = (p["ip"], p["port"])
        if key not in seen:
            seen.add(key)
            unique.append(p)
    return unique[:max_proxies]


