# ── Bézier Curve Mouse Movement ──

def bezier_point(points, t):
    """Evaluate a Bézier curve at parameter t using De Casteljau's algorithm.
    points: list of (x, y) control points
    t: parameter in [0, 1]
    Returns: (x, y) on the curve
    """
    pts = list(points)
    while len(pts) > 1:
        pts = [
            (
                pts[i][0] + t * (pts[i + 1][0] - pts[i][0]),
                pts[i][1] + t * (pts[i + 1][1] - pts[i][1]),
            )
            for i in range(len(pts) - 1)
        ]
    return pts[0]


def generate_bezier_path(start_x, start_y, end_x, end_y, num_ctrl=None, num_steps=None):
    """Generate a Bézier curve path from (start_x,start_y) to (end_x,end_y)
    with 3-6 random control points producing a natural curved trajectory.
    Returns list of (x,y) points along the curve.
    """
    if num_ctrl is None:
        num_ctrl = random.randint(3, 6)
    if num_steps is None:
        num_steps = random.randint(15, 25)

    pts = [(start_x, start_y)]
    dx = end_x - start_x
    dy = end_y - start_y
    dist = math.sqrt(dx * dx + dy * dy) if dx or dy else 1

    for i in range(1, num_ctrl):
        t = i / num_ctrl
        base_x = start_x + dx * t
        base_y = start_y + dy * t
        deviation = math.sin(t * math.pi)  # peaks at middle
        spread = max(dist * 0.40, 60)
        dev_x = random.uniform(-1.0, 1.0) * spread * deviation
        dev_y = random.uniform(-1.0, 1.0) * spread * deviation
        pts.append((base_x + dev_x, base_y + dev_y))

    pts.append((end_x, end_y))

    # Sample the curve at uniform intervals
    path = [bezier_point(pts, i / num_steps) for i in range(num_steps + 1)]
    return path


def bezier_mouse_move(driver, end_x, end_y):
    """Move mouse to (end_x, end_y) along a randomized Bézier curve path.
    Total path duration: 300-800ms via step-wise ActionChains.
    """
    try:
        vp = driver.execute_script("return [window.innerWidth, window.innerHeight]")
        if not vp or len(vp) != 2:
            vp = [1280, 720]

        # Start near viewport center with randomness
        start_x = vp[0] // 2 + random.randint(-80, 80)
        start_y = vp[1] // 2 + random.randint(-80, 80)

        path = generate_bezier_path(start_x, start_y, end_x, end_y)

        actions = ActionChains(driver)
        for i in range(1, len(path)):
            dx = path[i][0] - path[i - 1][0]
            dy = path[i][1] - path[i - 1][1]
            if abs(dx) < 0.5 and abs(dy) < 0.5:
                continue
            # Small per-step pause makes the movement smoother
            actions.move_by_offset(dx, dy)
        actions.perform()
        return True
    except Exception:
        return False


