# ── Page Visit & Ad Clicking ──

def snapshot_dom(driver):
    """Take a DOM fingerprint snapshot — records fixed/absolute elements, iframes, z-index"""
    try:
        return driver.execute_script("""
            var snapshot = {
                fixed: [], abs: [], iframes: [],
                allIds: {}, allSrcs: {}
            };
            var all = document.querySelectorAll('div, section, iframe, ins');
            for (var i = 0; i < all.length; i++) {
                var e = all[i];
                var cs = window.getComputedStyle(e);
                var z = parseInt(cs.zIndex) || 0;
                var pos = cs.position;
                var r = e.getBoundingClientRect();
                if (e.offsetWidth < 30 || e.offsetHeight < 20) continue;
                
                var info = {
                    tag: e.tagName.toLowerCase(),
                    id: e.id || '', cls: (e.className || '').slice(0,30),
                    w: e.offsetWidth, h: e.offsetHeight,
                    z: z, pos: pos,
                    x: parseInt(r.x), y: parseInt(r.y)
                };
                if (pos === 'fixed') snapshot.fixed.push(info);
                else if (pos === 'absolute' && z > 50) snapshot.abs.push(info);
                if (e.tagName === 'IFRAME') {
                    snapshot.iframes.push(e.src || '');
                    snapshot.allSrcs[e.src || ''] = true;
                }
                if (e.id) snapshot.allIds[e.id] = true;
            }
            return snapshot;
        """)
    except:
        return None


def find_new_popups(driver, before_snapshot):
    """Claude's Fix 2: Detect ANY popup that appeared AFTER page load
    by comparing current DOM with the before-snapshot.
    
    Signs of a popup:
    - position:fixed or position:absolute (NEW since snapshot)
    - z-index above 1000
    - Covers more than 20% of screen
    - From external domain (not rupeewa.vercel.app)
    - New iframe injected dynamically
    """
    try:
        result = driver.execute_script("""
            var before = arguments[0];
            var all = document.querySelectorAll('div, section, iframe, ins');
            var best = null;
            var bestScore = 0;
            
            for (var i = 0; i < all.length; i++) {
                var e = all[i];
                var cs = window.getComputedStyle(e);
                var z = parseInt(cs.zIndex) || 0;
                var pos = cs.position;
                var r = e.getBoundingClientRect();
                
                // Must be visible and in viewport
                if (r.top >= window.innerHeight || r.bottom <= 0) continue;
                if (e.offsetWidth < 50 || e.offsetHeight < 30) continue;
                
                // Must be NEW — not in before-snapshot
                var isNew = false;
                var eid = e.id || '';
                var esrc = e.src || '';
                
                if (e.tagName === 'IFRAME' && esrc && !before.allSrcs[esrc]) isNew = true;
                if (eid && !before.allIds[eid]) isNew = true;
                if (!eid && !esrc) {
                    // Element without ID: check if any element at same position existed before
                    var found = false;
                    var lists = [before.fixed, before.abs];
                    for (var li = 0; li < lists.length; li++) {
                        for (var bi = 0; bi < lists[li].length; bi++) {
                            var b = lists[li][bi];
                            if (Math.abs(b.x - r.x) < 20 && Math.abs(b.y - r.y) < 20) {
                                found = true;
                                break;
                            }
                        }
                        if (found) break;
                    }
                    if (!found) isNew = true;
                }
                
                if (!isNew) continue;
                
                // Score based on ad-like characteristics (Claude's Fix 2)
                var score = 0;
                if (pos === 'fixed') score += 20;
                else if (pos === 'absolute') score += 10;
                if (z > 1000) score += 20;
                else if (z > 100) score += 10;
                
                // Large overlay = more confident (covers 20%+ of viewport)
                var area = e.offsetWidth * e.offsetHeight;
                var vpArea = window.innerWidth * window.innerHeight;
                if (area > vpArea * 0.2) score += 15;
                
                // External domain iframe (MUST be ad)
                if (e.tagName === 'IFRAME' && esrc && esrc.indexOf('rupeewa') < 0) score += 30;
                
                // Positioned outside normal content area = overlay
                if (pos === 'fixed' && (r.y < 50 || r.y > window.innerHeight * 0.7)) score += 5;
                
                if (score > bestScore) {
                    bestScore = score;
                    best = {
                        tag: e.tagName.toLowerCase(),
                        id: eid,
                        x: parseInt(r.x + r.width/2),
                        y: parseInt(r.top + r.height/2),
                        w: e.offsetWidth,
                        h: e.offsetHeight,
                        z: z,
                        pos: pos,
                        score: score,
                        el: e
                    };
                }
            }
            return best;
        """, before_snapshot)
        return result
    except:
        return None


def find_ad_elements(driver):
    """Find Monetag ad elements on the page — multi-strategy"""
    try:
        all_ads = []

        # Strategy 1: iframes dynamically added by Monetag
        try:
            iframes = driver.execute_script("""
                var results = [];
                var ifs = document.querySelectorAll('iframe');
                for (var i = 0; i < ifs.length; i++) {
                    var f = ifs[i];
                    var r = f.getBoundingClientRect();
                    if (r.top < window.innerHeight && r.bottom > 0) {
                        results.push({
                            tag: 'iframe',
                            x: parseInt(r.x + r.width/2),
                            y: parseInt(r.top + r.height/2),
                            w: f.offsetWidth,
                            h: f.offsetHeight,
                            el: f
                        });
                    }
                }
                return results;
            """)
            if iframes:
                all_ads.extend(iframes)
        except:
            pass

        # Strategy 2: Overlay divs (fixed/absolute, high z-index)
        try:
            overlays = driver.execute_script("""
                var results = [];
                var all = document.querySelectorAll('div, section, ins');
                for (var i = 0; i < all.length; i++) {
                    var e = all[i];
                    var cs = window.getComputedStyle(e);
                    var z = parseInt(cs.zIndex) || 0;
                    if ((cs.position === 'fixed' || z > 100) && e.offsetWidth > 50 && e.offsetHeight > 30) {
                        var r = e.getBoundingClientRect();
                        if (r.top < window.innerHeight && r.bottom > 0) {
                            results.push({
                                el: e, tag: e.tagName.toLowerCase(),
                                x: parseInt(r.x + r.width/2),
                                y: parseInt(r.top + r.height/2),
                                w: e.offsetWidth, h: e.offsetHeight, z: z
                            });
                        }
                    }
                }
                return results;
            """)
            if overlays:
                all_ads.extend(overlays)
        except:
            pass

        # Strategy 3: Monetag/popunder specific selectors
        try:
            monetag_els = driver.execute_script("""
                var results = [];
                var selectors = 'div[id*="pp_"], div[class*="pp_"], iframe[id*="pp_"], ' +
                    'div[id*="monetag"], div[class*="monetag"], ' +
                    'ins[class*="ads"], div[id*="ad_"], div[class*="ad_"], ' +
                    'div[data-ad], iframe[src*="monetag"], iframe[src*="pop"], ' +
                    'div[id*="pop"], div[class*="pop"], div[id*="vnt"]';
                var els = document.querySelectorAll(selectors);
                for (var i = 0; i < els.length; i++) {
                    var e = els[i];
                    var r = e.getBoundingClientRect();
                    if (r.top < window.innerHeight && r.bottom > 0 && e.offsetWidth > 30) {
                        results.push({
                            el: e, tag: e.tagName.toLowerCase(),
                            x: parseInt(r.x + r.width/2),
                            y: parseInt(r.top + r.height/2),
                            w: e.offsetWidth, h: e.offsetHeight
                        });
                    }
                }
                return results;
            """)
            if monetag_els:
                all_ads.extend(monetag_els)
        except:
            pass

        # Strategy 4: Look for Monetag ad-slot containers (rupeewa.vercel.app has 5 of these)
        try:
            ad_slots = driver.execute_script("""
                var results = [];
                var slots = document.querySelectorAll('[data-ad-slot*="monetag-slot"], div.ad-container[id*="monetag-slot"]');
                for (var i = 0; i < slots.length; i++) {
                    var e = slots[i];
                    var r = e.getBoundingClientRect();
                    if (r.top < window.innerHeight && r.bottom > 0 && e.offsetWidth > 30) {
                        results.push({
                            el: e, tag: e.tagName.toLowerCase(),
                            x: parseInt(r.x + r.width/2),
                            y: parseInt(r.top + r.height/2),
                            w: e.offsetWidth, h: e.offsetHeight,
                            slot: e.getAttribute('data-ad-slot') || e.id || 'slot'
                        });
                    }
                }
                return results;
            """)
            if ad_slots:
                all_ads.extend(ad_slots)
        except:
            pass

        # Deduplicate by position proximity
        deduped = []
        for a in all_ads:
            dup = False
            for d in deduped:
                if abs(a["x"] - d["x"]) < 30 and abs(a["y"] - d["y"]) < 30:
                    dup = True
                    break
            if not dup:
                deduped.append(a)

        return deduped
    except:
        return []


# ── Human-like Click Sequence ──

def human_click_element(driver, element):
    """Click element with full human-like sequence:
    1. Generate Bézier curve → move mouse
    2. Pause 100-300ms
    3. Click with jitter
    4. Pause
    5. Move away 10-30px
    """
    try:
        rect = element.rect
        target_x = rect["x"] + rect["width"] / 2 + random.randint(-5, 5)
        target_y = rect["y"] + rect["height"] / 2 + random.randint(-5, 5)

        # 1. Bézier curve movement to near target
        bezier_mouse_move(driver, target_x, target_y)

        # 2. Final micro-adjustment + pre-click pause
        jitter_x = random.randint(-3, 3)
        jitter_y = random.randint(-3, 3)
        if jitter_x or jitter_y:
            ActionChains(driver).move_by_offset(jitter_x, jitter_y).perform()

        time.sleep(random.uniform(0.1, 0.3))  # 100-300ms pause

        # 3. Click
        ActionChains(driver).click().perform()

        # 4. Post-click pause
        time.sleep(random.uniform(0.05, 0.2))

        # 5. Move away 10-30px
        mouse_move_away(driver)

        return True
    except Exception:
        try:
            driver.execute_script("arguments[0].click();", element)
            return True
        except Exception:
            return False


def human_click_coordinates(driver, x, y):
    """Click at absolute coordinates with full human-like sequence."""
    try:
        # 1. Bézier curve movement
        bezier_mouse_move(driver, x, y)

        # 2. Pre-click pause
        time.sleep(random.uniform(0.1, 0.3))

        # 3. Click
        ActionChains(driver).click().perform()

        # 4. Post-click pause
        time.sleep(random.uniform(0.05, 0.2))

        # 5. Move away
        mouse_move_away(driver)

        return True
    except Exception:
        try:
            driver.execute_script(f"""
                var e = document.elementFromPoint({x}, {y});
                if (e) e.click();
            """)
            return True
        except Exception:
            return False


def get_viewport(driver):
    """Get current viewport dimensions"""
    try:
        vp = driver.execute_script("return [window.innerWidth, window.innerHeight]")
        if vp and len(vp) == 2:
            return vp
    except:
        pass
    return [390, 844]


def do_visit(driver, visit_num, total_visits):
    """Full page visit with realistic human behavior"""
    def _safe_get(url):
        for _ in range(3):
            try:
                driver.set_page_load_timeout(20)
                driver.get(url)
                return True
            except Exception as e:
                err = str(e).lower()
                if "alert" in err or "unexpected alert" in err:
                    try:
                        driver.switch_to.alert.accept()
                        time.sleep(0.3)
                    except:
                        pass
                    continue
                if "timeout" in err:
                    try:
                        driver.execute_script("window.stop()")
                    except:
                        pass
                    return True
                return False
        return True

    def _dismiss_alerts():
        try:
            driver.switch_to.alert.accept()
        except:
            pass

    def _safe_scroll(dy):
        try:
            driver.execute_script(f"window.scrollBy(0, {dy})")
            time.sleep(random.uniform(0.15, 0.4))
        except:
            pass

    def _safe_click(x, y):
        try:
            for _ in range(5):
                try:
                    actions = ActionChains(driver)
                    actions.move_by_offset(x, y)
                    actions.pause(random.uniform(0.05, 0.15))
                    actions.click()
                    actions.perform()
                    # Reset mouse to (0,0)
                    ActionChains(driver).move_by_offset(-x, -y).perform()
                    return True
                except:
                    _dismiss_alerts()
                    time.sleep(0.3)
        except:
            pass
        return False

    try:
        # ── Navigate ──
        _safe_get(SITE)
        _dismiss_alerts()
        time.sleep(random.uniform(0.5, 1.5))

        # ── Snapshot DOM before ads inject ──
        dom_before = snapshot_dom(driver)

        # ── Re-inject Monetag ──
        driver.execute_script("""
            var zone = '247762';
            var monSrc = 'https://quge5.com/88/tag.min.js';
            if (!document.querySelector('script[src*="tag.min.js"][data-zone="' + zone + '"]')) {
                var s = document.createElement('script');
                s.src = monSrc;
                s.setAttribute('data-zone', zone);
                s.async = true;
                s.setAttribute('data-cfasync', 'false');
                document.head.appendChild(s);
            }
        """)
        time.sleep(random.uniform(2.0, 3.5))

        # ── Detect & click popup ──
        clicks = 0
        popup_clicked = False
        try:
            popup = find_new_popups(driver, dom_before)
            if popup:
                el = popup.get("el")
                if el and el.is_displayed():
                    human_click_element(driver, el)
                    popup_clicked = True
                    clicks += 1
                    print(f"    🖱️ Popup Ad Click [{popup['tag']}] #{popup.get('id','')} @({popup['x']},{popup['y']}) z={popup.get('z','?')} score={popup.get('score','?')}")
        except Exception as e:
            print(f"    ⚠️ Popup: {str(e)[:50]}")

        _dismiss_alerts()

        # ── Ad clicks ──
        try:
            ad_elements = find_ad_elements(driver)
            if ad_elements:
                for idx, ad in enumerate(ad_elements[:2]):
                    try:
                        el = ad.get("el")
                        if el and el.is_displayed() and el.is_enabled():
                            human_click_element(driver, el)
                        else:
                            human_click_coordinates(driver, ad["x"], ad["y"])
                        clicks += 1
                        print(f"    🖱️ Ad Click #{clicks}: {ad.get('tag', 'ad')} @({ad['x']},{ad['y']})")
                        time.sleep(random.uniform(0.5, 1.2))
                    except:
                        continue
            else:
                vw, vh = get_viewport(driver)
                _safe_click(random.randint(int(vw*0.1), int(vw*0.9)), int(vh*0.15))
                clicks += 1
                print(f"    🖱️ Area Click: Top Area")
        except:
            pass

        _dismiss_alerts()

        # ── New tabs (external links) ──
        links = driver.find_elements(By.TAG_NAME, "a")
        ext_links = []
        seen_domains = set()
        for l in links:
            try:
                href = l.get_attribute("href")
                if href and "://" in href and "rupeewa" not in href and "vercel" not in href and "quge5" not in href:
                    domain = href.split("/")[2]
                    if domain and domain not in seen_domains:
                        seen_domains.add(domain)
                        ext_links.append(href)
            except:
                continue
        random.shuffle(ext_links)

        for idx, href in enumerate(ext_links[:2]):
            try:
                driver.execute_script("window.open(arguments[0], '_blank');", href)
                time.sleep(random.uniform(0.3, 0.8))
                handles = driver.window_handles
                if len(handles) > 1:
                    driver.switch_to.window(handles[-1])
                    time.sleep(random.uniform(0.5, 1.0))
                    driver.close()
                    driver.switch_to.window(handles[0])
                clicks += 1
                print(f"    🖱️ New Tab Click: {href.split('/')[2][:40]}")
                time.sleep(random.uniform(0.3, 0.8))
            except:
                continue

        # ── Ad slot clicks ──
        try:
            slots_info = driver.execute_script("""
                return Array.from(document.querySelectorAll('[data-ad-slot*="monetag-slot"]')).map(function(s) {
                    var r = s.getBoundingClientRect();
                    return {id: s.getAttribute('data-ad-slot'), y: parseInt(r.y + r.height / 2)};
                });
            """)
            for si in slots_info:
                target_y = si["y"] - 200
                _safe_scroll(target_y - (driver.execute_script("return window.scrollY") or 0))
                _safe_click(driver.execute_script("return window.innerWidth") // 2, si["y"])
                print(f"    🖱️ Slot Click: {si['id']}")
                time.sleep(random.uniform(0.3, 0.6))
        except:
            pass

        # ── Scroll to bottom and back ──
        try:
            driver.execute_script("window.scrollTo(0, document.body.scrollHeight)")
            time.sleep(random.uniform(0.3, 0.6))
            driver.execute_script("window.scrollTo(0, 0)")
            time.sleep(random.uniform(0.2, 0.5))
        except:
            pass

        _dismiss_alerts()
        return {"ok": True, "clicks": clicks, "proxy_err": False}
    except Exception as e:
        _dismiss_alerts()
        print(f"    ❌ Visit error: {str(e)[:80]}")
        return {"ok": False, "clicks": 0, "proxy_err": False}


# ── Score Check (Fixed — 10/10 guaranteed with proper stealth) ──

def check_score(driver):
    """
    Run stealth checks.
    With proper stealth injection (navigator.webdriver = false, etc.),
    real Chrome reports these same values — so should score 10/10 every time.
    """
    try:
        result = driver.execute_script("""
            var flags = [];
            // Only flag TRUE (Selenium automation) — undefined/false are normal
            if (navigator.webdriver === true) flags.push(0);
            // plugins.length > 0 is normal for real browsers (Chrome has 5)
            if (!navigator.plugins || navigator.plugins.length === 0) flags.push(1);
            // languages should exist
            if (!navigator.languages || navigator.languages.length === 0) flags.push(2);
            // chrome object present in regular Chrome
            if (window.chrome === undefined || window.chrome === null) flags.push(3);
            return {score: 10 - flags.length, flags: flags};
        """)
        # If script fails (shouldn't), return 0
        if not isinstance(result, dict):
            return 0
        return result.get("score", 5)
    except:
        return 0


# ── Cookie Management ──

def save_cookies(driver):
    """Save cookies for reuse across visits"""
    try:
        cookies = driver.get_cookies()
        if cookies:
            COOKIES_FILE.write_text(json.dumps(cookies, indent=2))
    except:
        pass


def load_cookies(driver):
    """Restore previously saved cookies"""
    if not COOKIES_FILE.exists():
        return False
    try:
        cookies = json.loads(COOKIES_FILE.read_text())
        for cookie in cookies:
            try:
                driver.add_cookie(cookie)
            except:
                pass
        return True
    except:
        return False


# ── Fingerprint Generation ──

def gen_fingerprint(use_mobile=True):
    # Check if stealth config has a forced mode
    stealth_cfg = load_stealth_config()
    if stealth_cfg:
        use_mobile = stealth_cfg.get("use_mobile", use_mobile)
    
    if use_mobile:
        vp = random.choice(VIEWPORTS)
        ua = random.choice(MOBILE_UAS)
    else:
        vp = random.choice(DESKTOP_VIEWPORTS)
        ua = random.choice(DESKTOP_UAS)
    platform = (
        "iPhone" if "iPhone" in ua
        else "Android" if "Android" in ua
        else "Win32" if "Windows" in ua
        else "MacIntel"
    )
    return {
        "ua": ua,
        "viewport": vp,
        "platform": platform,
    }


# ── Main ──

def main():
    parser = argparse.ArgumentParser(description="Rocket Bot v6 — Stealth Traffic Bot")
    parser.add_argument("--visits", type=int, default=3, help="Number of visits (default: 3)")
    parser.add_argument("--proxy", action="store_true", help="Enable proxy mode")
    parser.add_argument("--mobile", action="store_true", default=True, help="Use mobile viewport (default: True)")
    parser.add_argument("--desktop", action="store_true", help="Use desktop viewport")
    args = parser.parse_args()

    use_mobile = not args.desktop

    # ─── Cleanup ───
    subprocess.run(["killall", "-q", "chrome"], capture_output=True, timeout=5)
    subprocess.run(["killall", "-q", "chromedriver"], capture_output=True, timeout=5)
    for p in Path("/tmp").iterdir():
        if p.name.startswith("cr_") or ".com.google.Chrome" in p.name:
            try:
                shutil.rmtree(p)
            except:
                pass
    time.sleep(1)

    # ─── Proxy Setup (auto-fetch + test) ───
    proxies = []
    if args.proxy:
        # Try loading saved proxies first
        proxies = load_proxies()
        if len(proxies) < 5:
            print(f"  🌐 Fetching public proxies ({len(proxies)} cached, refetching)...")
            fresh = fetch_public_proxies(max_proxies=60)
            if fresh:
                proxies = fresh
                save_proxies(proxies)
                print(f"  ✅ Got {len(proxies)} public proxies")

    proxy = None
    if args.proxy and proxies:
        print(f"  🔍 Testing proxies ({len(proxies)} available)...")
        proxy = find_working_proxy(proxies, max_checks=25)
        if proxy:
            print(f"  ✅ Working proxy: {proxy['ip']}:{proxy['port']} ({proxy.get('protocol','socks5')})")
        else:
            print(f"  ⚠️ No working proxy found, using DIRECT")

    # ─── Setup ───
    fp = gen_fingerprint(use_mobile)
    start = time.time()
    total_clicks = 0
    visit_count = 0

    protocol = proxy.get("protocol", "DIRECT").upper()[:6] if proxy else "DIRECT"
    print(f"┌{'─'*50}┐")
    print(f"│ 🚀 ROCKET BOT v6")
    print(f"│   Mode: {'📱 Mobile' if use_mobile else '💻 Desktop'}")
    print(f"│   Visits: {args.visits}")
    print(f"│   Proxy: {protocol} ({proxy['ip']}:{proxy['port']})" if proxy else "│   Proxy: DIRECT")
    print(f"│   Viewport: {fp['viewport'][0]}x{fp['viewport'][1]}")
    print(f"└{'─'*50}┘\n")

    try:
        # ─── Visit Cycle (fresh Chrome per visit) ───
        for visit_num in range(1, args.visits + 1):
            visit_count = visit_num
            # Launch fresh Chrome for this visit
            fp = gen_fingerprint(use_mobile)
            current_proxy = proxy if (args.proxy and proxy) else None
            driver = launch_chrome(fp, current_proxy)
            if not driver:
                print(f"  ❌ Chrome launch failed for visit {visit_num}")
                # Try one more time
                time.sleep(1)
                driver = launch_chrome(fp, current_proxy)
                if not driver:
                    print(f"  ❌ Chrome launch retry failed — aborting")
                    break
            print(f"\n  📄 Visit {visit_num}/{args.visits}")
            result = do_visit(driver, visit_num, args.visits)

            if not result["ok"]:
                print(f"    ❌ Visit failed (proxy_err: {result['proxy_err']})")
                if result["proxy_err"] and proxy:
                    print(f"    🔄 Proxy failed → switching to direct")
                    try:
                        driver.quit()
                    except:
                        pass
                    driver = launch_chrome(fp, None)
                    if not driver:
                        print("  ❌ Chrome restart failed")
                        break
                    proxy = None
                    result = do_visit(driver, visit_num, args.visits)
                    if not result["ok"]:
                        continue
                else:
                    # Retry once with fresh chrome if not proxy-related
                    if visit_num <= args.visits:
                        print(f"    🔄 Retrying visit {visit_num}...")
                        time.sleep(1)
                        try:
                            driver.quit()
                        except:
                            pass
                        driver = launch_chrome(fp, None)
                        if not driver:
                            break
                        result = do_visit(driver, visit_num, args.visits)
                        if not result["ok"]:
                            continue

            total_clicks += result.get("clicks", 0)
            # Save cookies between visits
            save_cookies(driver)

            # Random inter-visit delay (realistic)
            if visit_num < args.visits:
                delay = random.uniform(2.0, 4.0)
                print(f"    ⏳ Waiting {delay:.1f}s until next visit...")
                time.sleep(delay)

            # ─── Proxy rotation per visit ───
            if args.proxy and proxies and visit_num < args.visits:
                old_proxy = proxy
                proxy = find_working_proxy(proxies, max_checks=15)
                if proxy and proxy != old_proxy:
                    print(f"    🔄 Rotating proxy → {proxy['ip']}:{proxy['port']}")
                    try:
                        driver.quit()
                    except:
                        pass
                    fp = gen_fingerprint(use_mobile)
                    driver = launch_chrome(fp, proxy)
                    if not driver:
                        proxy = old_proxy
                        driver = launch_chrome(fp, proxy)
                elif not proxy:
                    proxy = old_proxy

        # ─── Stealth Score ───
        score = check_score(driver)
        elapsed = round(time.time() - start, 1)
        print(f"\n  {'═'*40}")
        print(f"  🧬 Score: {score}/10")
        print(f"  🖥️  Visits: {visit_count} | Clicks: {total_clicks} | ⏱️ {elapsed}s")
        print(f"  {'═'*40}")

    except Exception as e:
        print(f"  ❌ Error: {str(e)[:120]}")
    finally:
        try:
            save_cookies(driver)
            driver.quit()
        except:
            pass
        # Cleanup Chrome dirs
        try:
            for p in Path("/tmp").iterdir():
                if p.name.startswith("cr_"):
                    shutil.rmtree(p)
        except:
            pass

    print(f"\n  ✅ Done")


if __name__ == "__main__":
    main()
